<template>
  <div style="padding: 2rem;">
    <h1>🗄️ Administrador de Base de Datos</h1>
    <p>Estado del store: {{ storeState }}</p>
    <button @click="testFetch">Test Fetch</button>
    <pre>{{ debug }}</pre>
  </div>
</template>

<script>
import { useDatabaseStore } from '../stores/database.store';

export default {
  name: 'DatabaseAdmin',
  setup() {
    const databaseStore = useDatabaseStore();
    return { databaseStore };
  },
  data() {
    return {
      debug: 'Iniciando...'
    };
  },
  computed: {
    storeState() {
      return JSON.stringify({
        tables: this.databaseStore.tables.length,
        loading: this.databaseStore.loading,
        error: this.databaseStore.error
      });
    }
  },
  methods: {
    async testFetch() {
      console.log('[testFetch] Iniciando...');
      this.debug = 'Cargando...';
      try {
        await this.databaseStore.fetchTables();
        this.debug = 'Tablas: ' + JSON.stringify(this.databaseStore.tables);
      } catch (error) {
        this.debug = 'Error: ' + error.message;
      }
    }
  },
  mounted() {
    console.log('[DatabaseAdmin] Mounted');
    this.debug = 'Componente montado';
  }
};
</script>

<style scoped>
/* Simple styles */
</style>
